import React, {useEffect} from 'react';
import {Linking, Text, View} from 'react-native';
import {NavigationContainer, createNavigationContainerRef} from '@react-navigation/native';
import {createStackNavigator} from '@react-navigation/stack';

const Stack = createStackNavigator();
export const navigationRef = createNavigationContainerRef();

function navigate(name, params) {
  if (navigationRef.isReady()) {
    navigationRef.navigate(name, params);
  }
}

function parseAndNavigate(url) {
  if (!url) return;
  const [, path = ''] = url.split('://');        // profile/123 or payment/confirm
  const [route, param] = path.split('/');
  switch (route) {
    case 'profile':
      navigate('Profile', {userId: param});
      break;
    case 'payment':
      if (param === 'confirm') navigate('PaymentConfirm');
      break;
    default:
      break;
  }
}

function useDeepLinking() {
  useEffect(() => {
    const handleUrl = ({url}) => parseAndNavigate(url);
    Linking.getInitialURL().then(url => parseAndNavigate(url));
    const sub = Linking.addEventListener('url', handleUrl);
    return () => sub.remove();
  }, []);
}

function ProfileScreen({route}) {
  return (
    <View style={{flex: 1, alignItems: 'center', justifyContent: 'center'}}>
      <Text>Profile Screen</Text>
      <Text>User ID: {route.params?.userId}</Text>
    </View>
  );
}

function PaymentConfirmScreen() {
  return (
    <View style={{flex: 1, alignItems: 'center', justifyContent: 'center'}}>
      <Text>Payment Confirmation</Text>
    </View>
  );
}

export default function App() {
  useDeepLinking();
  return (
    <NavigationContainer ref={navigationRef}>
      <Stack.Navigator initialRouteName="Profile">
        <Stack.Screen name="Profile" component={ProfileScreen} />
        <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
}